-- KeretaAI - Seed Data
-- 14 users, 28 sellers (all Malaysian states + KL/Putrajaya/Labuan), 100 second-hand cars
-- Realistic Malaysian used-car market pricing (RM)
--
-- DealScore formula (0-100):
--   price_vs_market * 0.40   (below market_min=100, within range=70, above max=30)
--   + mileage_vs_age * 0.30  (<15k km/yr=100, 15-20k=70, >20k=40)
--   + recency * 0.15         (<=3 yrs old=100, 4-6=70, >6=40)
--   + seller_trust * 0.15    (verified dealer=100, dealer=80, private=60)

-- ============================================================
-- TRUNCATE (safe re-seed)
-- ============================================================
TRUNCATE cars, sellers, users, conversations RESTART IDENTITY CASCADE;

